// Extract and validate Facebook lead data for final expense
const leadData = $input.first().json;

// Initialize lead object with final expense specific fields
const lead = {
  id: leadData.leadgen_id || leadData.id || `lead_${Date.now()}`,
  name: '',
  phone: '',
  email: '',
  beneficiary: '',
  dob: '',
  state: '',
  age: null,
  form_id: leadData.form_id,
  ad_id: leadData.ad_id,
  campaign_id: leadData.campaign_id,
  created_time: leadData.created_time || new Date().toISOString(),
  source: 'facebook_final_expense_ad'
};

// Parse Facebook field_data array
if (leadData.field_data && Array.isArray(leadData.field_data)) {
  leadData.field_data.forEach(field => {
    const fieldName = field.name?.toLowerCase();
    const value = field.values?.[0] || '';

    if (fieldName?.includes('full_name') || fieldName?.includes('name')) {
      lead.name = value;
    } else if (fieldName?.includes('phone') || fieldName?.includes('number')) {
      lead.phone = value.replace(/[^0-9+]/g, ''); // Clean phone number
    } else if (fieldName?.includes('email')) {
      lead.email = value;
    } else if (fieldName?.includes('beneficiary')) {
      lead.beneficiary = value;
    } else if (fieldName?.includes('state')) {
      lead.state = value;
    } else if (fieldName?.includes('date_of_birth') || fieldName?.includes('dob')) {
      lead.dob = value;
      // Calculate age for lead scoring
      if (value) {
        const birthDate = new Date(value);
        const today = new Date();
        lead.age = today.getFullYear() - birthDate.getFullYear();
        const monthDiff = today.getMonth() - birthDate.getMonth();
        if (monthDiff < 0 || (monthDiff === 0 && today.getDate() < birthDate.getDate())) {
          lead.age--;
        }
      }
    }
  });
}

// Validate required fields for final expense
if (!lead.phone) {
  throw new Error('Phone number is required for auto-dialing');
}
if (!lead.name) {
  throw new Error('Name is required for final expense leads');
}

// Lead scoring for final expense (age-based)
let leadScore = 0;
if (lead.age) {
  if (lead.age >= 50 && lead.age <= 65) leadScore += 40; // Prime age
  if (lead.age >= 66 && lead.age <= 80) leadScore += 35; // Good age
  if (lead.age >= 81) leadScore += 20; // Older demographic
}
if (lead.beneficiary) leadScore += 25; // Has beneficiary
if (lead.email) leadScore += 15; // Email provided
if (lead.dob) leadScore += 10; // DOB provided
if (lead.state) leadScore += 5; // State provided

lead.score = leadScore;
lead.priority = leadScore >= 70 ? 'high' : leadScore >= 50 ? 'medium' : 'low';

// Initialize call tracking
lead.call_attempts = 0;
lead.last_call_time = null;
lead.status = 'new';
lead.next_action_time = new Date().toISOString();

// Detect time zone based on state
const stateTimeZones = {
  'AL': 'America/Chicago', 'AK': 'America/Anchorage', 'AZ': 'America/Phoenix',
  'AR': 'America/Chicago', 'CA': 'America/Los_Angeles', 'CO': 'America/Denver',
  'CT': 'America/New_York', 'DE': 'America/New_York', 'FL': 'America/New_York',
  'GA': 'America/New_York', 'HI': 'Pacific/Honolulu', 'ID': 'America/Denver',
  'IL': 'America/Chicago', 'IN': 'America/New_York', 'IA': 'America/Chicago',
  'KS': 'America/Chicago', 'KY': 'America/New_York', 'LA': 'America/Chicago',
  'ME': 'America/New_York', 'MD': 'America/New_York', 'MA': 'America/New_York',
  'MI': 'America/New_York', 'MN': 'America/Chicago', 'MS': 'America/Chicago',
  'MO': 'America/Chicago', 'MT': 'America/Denver', 'NE': 'America/Chicago',
  'NV': 'America/Los_Angeles', 'NH': 'America/New_York', 'NJ': 'America/New_York',
  'NM': 'America/Denver', 'NY': 'America/New_York', 'NC': 'America/New_York',
  'ND': 'America/Chicago', 'OH': 'America/New_York', 'OK': 'America/Chicago',
  'OR': 'America/Los_Angeles', 'PA': 'America/New_York', 'RI': 'America/New_York',
  'SC': 'America/New_York', 'SD': 'America/Chicago', 'TN': 'America/Chicago',
  'TX': 'America/Chicago', 'UT': 'America/Denver', 'VT': 'America/New_York',
  'VA': 'America/New_York', 'WA': 'America/Los_Angeles', 'WV': 'America/New_York',
  'WI': 'America/Chicago', 'WY': 'America/Denver'
};

lead.timeZone = stateTimeZones[lead.state?.toUpperCase()] || 'America/New_York';

return { lead };

