  // Best: 9-11:30 AM, 1-3 PM, 5-7 PM in prospect's timezone
  // Avoid: Before 9 AM, lunch (11:30-1), after 8 PM, Sundays

  if (day === 0) return false; // No Sunday calls

  // Saturday: limited hours 10 AM - 5 PM
  if (day === 6) return hour >= 10 && hour < 17;

  // Weekdays: optimal windows
  const morningWindow = hour >= 9 && hour < 11.5; // 9:00-11:30 AM
  const afternoonWindow = hour >= 13 && hour < 15; // 1:00-3:00 PM  
  const eveningWindow = hour >= 17 && hour < 19; // 5:00-7:00 PM

  return morningWindow || afternoonWindow || eveningWindow;
}}

