// Determine call success based on qualification and transfer to licensed agent
const callData = $node['Check Call Status'].json;
const leadData = $node['Process Final Expense Lead Data'].json.lead;

// Success criteria: Lead qualified and transferred to licensed agent
const callStatus = callData.call_status || 'failed';
const callDuration = callData.call_analysis?.duration || 0;
const wasAnswered = callData.call_analysis?.answered || false;
const wasTransferred = callData.call_analysis?.transferred || false;
const qualificationScore = callData.call_analysis?.qualification_score || 0;
const conversationSummary = callData.call_analysis?.summary || '';

// Define success criteria - YOUR SPECIFICATION: qualified and transferred to licensed agent
let isSuccessful = false;
let successReason = '';

if (callStatus === 'completed' && wasAnswered) {
  // Primary success: Lead was qualified and transferred to licensed agent
  if (wasTransferred && qualificationScore > 0.6) {
    isSuccessful = true;
    successReason = 'qualified_and_transferred';
  }
  // Secondary success: High qualification but no immediate transfer (follow-up scheduled)
  else if (qualificationScore > 0.7 && callDuration >= 180) {
    isSuccessful = true;
    successReason = 'highly_qualified_followup_scheduled';
  }
  // Moderate success: Some interest shown, worth follow-up
  else if (qualificationScore > 0.4 && callDuration >= 120) {
    isSuccessful = true;
    successReason = 'interested_followup_needed';
  }
}

// If not successful, determine retry logic
let shouldRetry = true;
let nextRetryHours = 0;

const currentAttempt = leadData.call_attempts + 1;

if (currentAttempt >= 4) {
  shouldRetry = false; // Max 4 attempts for final expense
} else if (!wasAnswered) {
  // Progressive retry timing for no answer
  switch(currentAttempt) {
    case 1:
      nextRetryHours = 3; // 3 hours later, different time window
      break;
    case 2:
      nextRetryHours = 24; // Next day, optimal time
      break;
    case 3:
      nextRetryHours = 72; // 3 days later (seniors need time to consider)
      break;
  }
} else {
  // If answered but not qualified, longer wait times
  switch(currentAttempt) {
    case 1:
      nextRetryHours = 48; // 2 days for answered but unqualified
      break;
    case 2:
      nextRetryHours = 168; // 1 week
      break;
    case 3:
      shouldRetry = false; // Don't retry if answered multiple times but not qualified
      break;
  }
}

return {
  callResult: {
    isSuccessful,
    successReason,
    shouldRetry,
    nextRetryHours,
    callDuration,
    wasAnswered,
    wasTransferred,
    qualificationScore,
    conversationSummary,
    currentAttempt
  }
};

