={{ 
  const leadData = $node['Process Final Expense Lead Data'].json.lead;
  const timeZone = leadData.timeZone || 'America/New_York';

  // Get current time in prospect's timezone to find next optimal calling time
  const now = new Date();
  const prospectTime = new Date(now.toLocaleString('en-US', {timeZone}));
  const hour = prospectTime.getHours();
  const day = prospectTime.getDay();

  // If it's outside optimal hours, wait until next optimal window
  if (day === 0) { // Sunday
    // Wait until Monday 9 AM
    const hoursUntilMonday = 24 + (9 - hour);
    return hoursUntilMonday > 0 ? hoursUntilMonday : 1;
  }

  // Find next optimal calling window
  if (hour < 9) {
    return 9 - hour; // Wait until 9 AM
  } else if (hour >= 11.5 && hour < 13) {
    return 13 - hour; // Wait until 1 PM
  } else if (hour >= 15 && hour < 17) {
    return 17 - hour; // Wait until 5 PM
  } else if (hour >= 19) {
    return 24 - hour + 9; // Wait until next day 9 AM
  }

  return 1; // Default 1 hour wait
}}
